/**
 * Formula Engine
 *
 * Evaluates simple formula expressions for custom formula fields.
 * Supports basic math operations, logic, and functions.
 *
 * SECURITY: Does not use eval(). Custom parser for safety.
 *
 * Supported:
 * - Math: +, -, *, /
 * - Logic: IF(condition, trueValue, falseValue)
 * - Functions: SUM(a, b, ...), AVERAGE(a, b, ...), COUNT(a, b, ...), DAYS_BETWEEN(date1, date2)
 * - Comparisons: =, !=, <, >, <=, >=
 * - Field references: {fieldId}
 */

import type { CustomFieldsMap } from '../types/customFields';

export type FormulaValue = number | string | boolean | null;

export interface FormulaEvaluationResult {
  value: FormulaValue;
  error?: string;
}

/**
 * Evaluate a formula expression with field values
 */
export function evaluateFormula(
  expression: string,
  fieldValues: CustomFieldsMap
): FormulaEvaluationResult {
  try {
    // Replace field references {fieldId} with actual values
    const resolvedExpression = resolveFieldReferences(expression, fieldValues);

    // Parse and evaluate the expression
    const value = parseExpression(resolvedExpression);

    return { value };
  } catch (error) {
    return {
      value: null,
      error: error instanceof Error ? error.message : 'Invalid formula',
    };
  }
}

/**
 * Replace {fieldId} references with actual field values
 */
function resolveFieldReferences(
  expression: string,
  fieldValues: CustomFieldsMap
): string {
  return expression.replace(/\{([^}]+)\}/g, (match, fieldId) => {
    const value = fieldValues[fieldId];

    if (value === null || value === undefined) {
      return '0'; // Default to 0 for missing values
    }

    // Convert to string representation
    if (typeof value === 'string') {
      return `"${value}"`; // Wrap strings in quotes
    }

    return String(value);
  });
}

/**
 * Parse and evaluate an expression
 */
function parseExpression(expr: string): FormulaValue {
  const trimmed = expr.trim();

  // Handle IF function: IF(condition, trueValue, falseValue)
  if (trimmed.toUpperCase().startsWith('IF(')) {
    return evaluateIf(trimmed);
  }

  // Handle SUM function: SUM(a, b, c, ...)
  if (trimmed.toUpperCase().startsWith('SUM(')) {
    return evaluateSum(trimmed);
  }

  // Handle AVERAGE function: AVERAGE(a, b, c, ...)
  if (trimmed.toUpperCase().startsWith('AVERAGE(')) {
    return evaluateAverage(trimmed);
  }

  // Handle COUNT function: COUNT(a, b, c, ...)
  if (trimmed.toUpperCase().startsWith('COUNT(')) {
    return evaluateCount(trimmed);
  }

  // Handle DAYS_BETWEEN function: DAYS_BETWEEN(date1, date2)
  if (trimmed.toUpperCase().startsWith('DAYS_BETWEEN(')) {
    return evaluateDaysBetween(trimmed);
  }

  // Handle comparison operators
  if (trimmed.includes('=') || trimmed.includes('!=') || trimmed.includes('>') || trimmed.includes('<')) {
    return evaluateComparison(trimmed);
  }

  // Handle math operations: +, -, *, /
  if (trimmed.includes('+') || trimmed.includes('-') || trimmed.includes('*') || trimmed.includes('/')) {
    return evaluateMath(trimmed);
  }

  // Handle literals
  return parseLiteral(trimmed);
}

/**
 * Evaluate IF(condition, trueValue, falseValue)
 */
function evaluateIf(expr: string): FormulaValue {
  const match = expr.match(/^IF\s*\((.*)\)$/i);
  if (!match) {
    throw new Error('Invalid IF syntax');
  }

  const args = splitArguments(match[1]);
  if (args.length !== 3) {
    throw new Error('IF requires 3 arguments: condition, trueValue, falseValue');
  }

  const condition = parseExpression(args[0]);
  const trueValue = parseExpression(args[1]);
  const falseValue = parseExpression(args[2]);

  return condition ? trueValue : falseValue;
}

/**
 * Evaluate SUM(a, b, c, ...)
 */
function evaluateSum(expr: string): number {
  const match = expr.match(/^SUM\s*\((.*)\)$/i);
  if (!match) {
    throw new Error('Invalid SUM syntax');
  }

  const args = splitArguments(match[1]);
  const numbers = args.map((arg) => {
    const value = parseExpression(arg);
    return typeof value === 'number' ? value : 0;
  });

  return numbers.reduce((sum, num) => sum + num, 0);
}

/**
 * Evaluate AVERAGE(a, b, c, ...)
 */
function evaluateAverage(expr: string): number {
  const match = expr.match(/^AVERAGE\s*\((.*)\)$/i);
  if (!match) {
    throw new Error('Invalid AVERAGE syntax');
  }

  const args = splitArguments(match[1]);
  if (args.length === 0) {
    return 0;
  }

  const numbers = args.map((arg) => {
    const value = parseExpression(arg);
    return typeof value === 'number' ? value : 0;
  });

  const sum = numbers.reduce((total, num) => total + num, 0);
  return sum / numbers.length;
}

/**
 * Evaluate COUNT(a, b, c, ...)
 */
function evaluateCount(expr: string): number {
  const match = expr.match(/^COUNT\s*\((.*)\)$/i);
  if (!match) {
    throw new Error('Invalid COUNT syntax');
  }

  const args = splitArguments(match[1]);
  return args.filter((arg) => {
    const value = parseExpression(arg);
    return value !== null && value !== undefined && value !== '';
  }).length;
}

/**
 * Evaluate DAYS_BETWEEN(date1, date2)
 */
function evaluateDaysBetween(expr: string): number {
  const match = expr.match(/^DAYS_BETWEEN\s*\((.*)\)$/i);
  if (!match) {
    throw new Error('Invalid DAYS_BETWEEN syntax');
  }

  const args = splitArguments(match[1]);
  if (args.length !== 2) {
    throw new Error('DAYS_BETWEEN requires 2 date arguments');
  }

  const date1Str = parseExpression(args[0]);
  const date2Str = parseExpression(args[1]);

  const date1 = new Date(String(date1Str));
  const date2 = new Date(String(date2Str));

  if (isNaN(date1.getTime()) || isNaN(date2.getTime())) {
    throw new Error('Invalid date format in DAYS_BETWEEN');
  }

  const diffMs = date2.getTime() - date1.getTime();
  return Math.floor(diffMs / (1000 * 60 * 60 * 24));
}

/**
 * Evaluate comparison: =, !=, <, >, <=, >=
 */
function evaluateComparison(expr: string): boolean {
  // Try <=, >=, !=, = first (order matters)
  let match = expr.match(/^(.+?)\s*(<=|>=|!=|=|<|>)\s*(.+)$/);

  if (!match) {
    throw new Error('Invalid comparison syntax');
  }

  const left = parseExpression(match[1]);
  const operator = match[2];
  const right = parseExpression(match[3]);

  switch (operator) {
    case '=':
      return left === right;
    case '!=':
      return left !== right;
    case '<':
      return Number(left) < Number(right);
    case '>':
      return Number(left) > Number(right);
    case '<=':
      return Number(left) <= Number(right);
    case '>=':
      return Number(left) >= Number(right);
    default:
      throw new Error(`Unknown operator: ${operator}`);
  }
}

/**
 * Evaluate math operations: +, -, *, /
 * Uses operator precedence: *, / before +, -
 */
function evaluateMath(expr: string): number {
  // Handle multiplication and division first
  let tokens = expr.split(/([+\-*/])/).map((t) => t.trim()).filter((t) => t);

  // Process * and / first
  for (let i = 1; i < tokens.length; i += 2) {
    const operator = tokens[i];
    if (operator === '*' || operator === '/') {
      const left = Number(tokens[i - 1]);
      const right = Number(tokens[i + 1]);

      if (operator === '/' && right === 0) {
        throw new Error('Division by zero');
      }

      const result = operator === '*' ? left * right : left / right;
      tokens.splice(i - 1, 3, String(result));
      i -= 2; // Adjust index after splice
    }
  }

  // Process + and -
  for (let i = 1; i < tokens.length; i += 2) {
    const operator = tokens[i];
    if (operator === '+' || operator === '-') {
      const left = Number(tokens[i - 1]);
      const right = Number(tokens[i + 1]);

      const result = operator === '+' ? left + right : left - right;
      tokens.splice(i - 1, 3, String(result));
      i -= 2; // Adjust index after splice
    }
  }

  if (tokens.length !== 1) {
    throw new Error('Invalid math expression');
  }

  return Number(tokens[0]);
}

/**
 * Parse a literal value (number, string, boolean, null)
 */
function parseLiteral(value: string): FormulaValue {
  const trimmed = value.trim();

  // Boolean
  if (trimmed.toLowerCase() === 'true') return true;
  if (trimmed.toLowerCase() === 'false') return false;

  // Null
  if (trimmed.toLowerCase() === 'null') return null;

  // String (quoted)
  if ((trimmed.startsWith('"') && trimmed.endsWith('"')) ||
      (trimmed.startsWith("'") && trimmed.endsWith("'"))) {
    return trimmed.slice(1, -1);
  }

  // Number
  const num = Number(trimmed);
  if (!isNaN(num)) {
    return num;
  }

  // Unknown - treat as string
  return trimmed;
}

/**
 * Split function arguments by commas (respecting nested parentheses)
 */
function splitArguments(argsStr: string): string[] {
  const args: string[] = [];
  let current = '';
  let depth = 0;
  let inString = false;
  let stringChar = '';

  for (let i = 0; i < argsStr.length; i++) {
    const char = argsStr[i];

    // Handle string delimiters
    if ((char === '"' || char === "'") && !inString) {
      inString = true;
      stringChar = char;
      current += char;
      continue;
    } else if (char === stringChar && inString) {
      inString = false;
      stringChar = '';
      current += char;
      continue;
    }

    // Skip if inside string
    if (inString) {
      current += char;
      continue;
    }

    // Handle parentheses depth
    if (char === '(') {
      depth++;
      current += char;
    } else if (char === ')') {
      depth--;
      current += char;
    } else if (char === ',' && depth === 0) {
      // Split here
      args.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }

  // Add last argument
  if (current.trim()) {
    args.push(current.trim());
  }

  return args;
}

/**
 * Detect circular references in formula
 */
export function detectCircularReferences(
  fieldId: string,
  referencedFields: string[],
  allFieldDefinitions: Array<{ id: string; referencedFields?: string[] }>
): boolean {
  const visited = new Set<string>();

  function dfs(currentId: string): boolean {
    if (visited.has(currentId)) {
      return true; // Circular reference detected
    }

    visited.add(currentId);

    const field = allFieldDefinitions.find((f) => f.id === currentId);
    if (!field || !field.referencedFields) {
      return false;
    }

    for (const refId of field.referencedFields) {
      if (dfs(refId)) {
        return true;
      }
    }

    visited.delete(currentId);
    return false;
  }

  // Check if any referenced field creates a cycle back to this field
  for (const refId of referencedFields) {
    if (refId === fieldId) {
      return true; // Self-reference
    }

    const field = allFieldDefinitions.find((f) => f.id === refId);
    if (field && field.referencedFields) {
      if (dfs(refId)) {
        return true;
      }
    }
  }

  return false;
}

/**
 * Extract field references from formula expression
 */
export function extractFieldReferences(expression: string): string[] {
  const matches = expression.matchAll(/\{([^}]+)\}/g);
  const refs = new Set<string>();

  for (const match of matches) {
    refs.add(match[1]);
  }

  return Array.from(refs);
}

/**
 * Person Field Editor Component
 *
 * Autocomplete dropdown for selecting people from the people list.
 * Supports single or multiple person selection.
 */

import { useState, useRef, useEffect } from 'react';
import { X, UserPlus } from 'lucide-react';
import { useSettingsStore } from '../../stores/useSettingsStore';

interface PersonFieldEditorProps {
  value: string | string[];
  allowMultiple: boolean;
  onChange: (value: string | string[]) => void;
  placeholder?: string;
  className?: string;
}

export function PersonFieldEditor({
  value,
  allowMultiple,
  onChange,
  placeholder = 'Select person...',
  className = '',
}: PersonFieldEditorProps) {
  const { peopleList, addPerson } = useSettingsStore();
  const [inputValue, setInputValue] = useState('');
  const [showDropdown, setShowDropdown] = useState(false);
  const [showAddDialog, setShowAddDialog] = useState(false);
  const [newPersonName, setNewPersonName] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Normalize value to array for easier handling
  const selectedPeople = Array.isArray(value) ? value : value ? [value] : [];

  // Filter people based on input and already selected
  const filteredPeople = peopleList.filter((person) => {
    const matchesInput = person.toLowerCase().includes(inputValue.toLowerCase());
    const notSelected = !selectedPeople.includes(person);
    return matchesInput && notSelected;
  });

  // Close dropdown when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node) &&
        inputRef.current &&
        !inputRef.current.contains(event.target as Node)
      ) {
        setShowDropdown(false);
      }
    }

    if (showDropdown) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [showDropdown]);

  const handleSelectPerson = (person: string) => {
    if (allowMultiple) {
      onChange([...selectedPeople, person]);
    } else {
      onChange(person);
      setShowDropdown(false);
    }
    setInputValue('');
  };

  const handleRemovePerson = (person: string) => {
    if (allowMultiple) {
      onChange(selectedPeople.filter((p) => p !== person));
    } else {
      onChange('');
    }
  };

  const handleAddNewPerson = () => {
    const trimmedName = newPersonName.trim();
    if (trimmedName && !peopleList.includes(trimmedName)) {
      addPerson(trimmedName);
      handleSelectPerson(trimmedName);
      setNewPersonName('');
      setShowAddDialog(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && filteredPeople.length > 0) {
      e.preventDefault();
      handleSelectPerson(filteredPeople[0]);
    } else if (e.key === 'Escape') {
      setShowDropdown(false);
    } else if (e.key === 'Backspace' && inputValue === '' && selectedPeople.length > 0) {
      // Remove last person on backspace when input is empty
      handleRemovePerson(selectedPeople[selectedPeople.length - 1]);
    }
  };

  return (
    <div className={`relative ${className}`}>
      {/* Selected People Pills */}
      {selectedPeople.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-2">
          {selectedPeople.map((person) => (
            <div
              key={person}
              className="inline-flex items-center gap-1 px-2 py-1 bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue dark:text-accent-blue-hover rounded text-sm"
            >
              <span className="font-medium">{getInitials(person)}</span>
              <span>{person}</span>
              <button
                onClick={() => handleRemovePerson(person)}
                className="hover:bg-accent-blue/20 dark:hover:bg-accent-blue/30 rounded p-0.5"
                aria-label={`Remove ${person}`}
              >
                <X className="w-3 h-3" />
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Input Field */}
      {(allowMultiple || selectedPeople.length === 0) && (
        <div className="relative">
          <input
            ref={inputRef}
            type="text"
            value={inputValue}
            onChange={(e) => {
              setInputValue(e.target.value);
              setShowDropdown(true);
            }}
            onFocus={() => setShowDropdown(true)}
            onKeyDown={handleKeyDown}
            placeholder={placeholder}
            className="w-full px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
            aria-label="Person selector"
            aria-autocomplete="list"
            aria-expanded={showDropdown}
          />

          {/* Dropdown */}
          {showDropdown && (
            <div
              ref={dropdownRef}
              className="absolute z-10 w-full mt-1 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg shadow-lg max-h-60 overflow-y-auto"
            >
              {filteredPeople.length > 0 ? (
                <ul className="py-1">
                  {filteredPeople.map((person) => (
                    <li key={person}>
                      <button
                        onClick={() => handleSelectPerson(person)}
                        className="w-full px-3 py-2 text-left hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark text-text-light-primary dark:text-text-dark-primary flex items-center gap-2"
                      >
                        <span className="flex items-center justify-center w-6 h-6 rounded-full bg-accent-blue/20 text-accent-blue text-xs font-medium">
                          {getInitials(person)}
                        </span>
                        <span>{person}</span>
                      </button>
                    </li>
                  ))}
                </ul>
              ) : (
                <div className="px-3 py-4 text-center text-text-light-secondary dark:text-text-dark-secondary text-sm">
                  {peopleList.length === 0 ? (
                    <>No people added yet</>
                  ) : (
                    <>No matching people found</>
                  )}
                </div>
              )}

              {/* Add New Person Button */}
              <div className="border-t border-border-light dark:border-border-dark">
                <button
                  onClick={() => setShowAddDialog(true)}
                  className="w-full px-3 py-2 text-left hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark text-accent-blue dark:text-accent-blue-hover flex items-center gap-2"
                >
                  <UserPlus className="w-4 h-4" />
                  <span>Add new person</span>
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Add New Person Dialog */}
      {showAddDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
              Add New Person
            </h3>

            <input
              type="text"
              value={newPersonName}
              onChange={(e) => setNewPersonName(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleAddNewPerson();
                } else if (e.key === 'Escape') {
                  setShowAddDialog(false);
                  setNewPersonName('');
                }
              }}
              placeholder="Enter person's name"
              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue mb-4"
              autoFocus
            />

            <div className="flex justify-end gap-2">
              <button
                onClick={() => {
                  setShowAddDialog(false);
                  setNewPersonName('');
                }}
                className="px-4 py-2 bg-surface-hover-light dark:bg-surface-hover-dark rounded-lg hover:bg-border-light dark:hover:bg-border-dark text-text-light-primary dark:text-text-dark-primary"
              >
                Cancel
              </button>
              <button
                onClick={handleAddNewPerson}
                disabled={!newPersonName.trim()}
                className="px-4 py-2 bg-accent-blue text-white rounded-lg hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Add
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * Get initials from person name
 */
function getInitials(name: string): string {
  const parts = name.trim().split(/\s+/);
  if (parts.length === 1) {
    return parts[0].charAt(0).toUpperCase();
  }
  return (parts[0].charAt(0) + parts[parts.length - 1].charAt(0)).toUpperCase();
}

